import { takaro, data } from '@takaro/helpers';

async function main() {
    const { gameServerId, module: mod } = data;
    const cronjobs = mod.userConfig.cronjobs || [];

    console.log('🔄 Dynamic Server Messages Generator starting...');

    // Server short ID for namespacing (first 8 chars of gameServerId)
    const serverShortId = gameServerId.substring(0, 8);
    const serverPrefix = `sm-${serverShortId}-`;

    console.log(`📍 Server: ${serverShortId} (${gameServerId})`);

    // State management keys
    const configHashKey = 'sm_config_hash';
    const lastProcessedKey = 'sm_last_processed';
    const backupConfigKey = 'sm_backup_config';

    try {
        // Create configuration hash for change detection
        const currentConfigHash = JSON.stringify(cronjobs).split('').reduce((a, b) => {
            a = ((a << 5) - a) + b.charCodeAt(0);
            return a & a;
        }, 0).toString();

        // Get stored state
        let storedHash = null;
        let lastProcessed = null;
        try {
            const hashVar = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [configHashKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });
            if (hashVar.data.data.length > 0) {
                storedHash = hashVar.data.data[0].value;
            }

            const processedVar = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [lastProcessedKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });
            if (processedVar.data.data.length > 0) {
                lastProcessed = new Date(processedVar.data.data[0].value);
            }
        } catch (error) {
            console.log('📝 No previous state found, treating as first run');
        }

        // Check if configuration changed (5 minute cooldown)
        if (storedHash === currentConfigHash && lastProcessed && (Date.now() - lastProcessed.getTime()) < 300000) {
            console.log('✅ No configuration changes detected, skipping update');
            return;
        }

        // Backup current configuration
        try {
            await takaro.variable.variableControllerCreate({
                key: backupConfigKey,
                value: JSON.stringify({
                    userConfig: mod.userConfig,
                    timestamp: new Date().toISOString(),
                    hash: currentConfigHash
                }),
                gameServerId,
                moduleId: mod.moduleId
            });
            console.log('💾 Configuration backup created');
        } catch (backupError) {
            const existingBackup = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [backupConfigKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });
            if (existingBackup.data.data.length > 0) {
                await takaro.variable.variableControllerUpdate(existingBackup.data.data[0].id, {
                    value: JSON.stringify({
                        userConfig: mod.userConfig,
                        timestamp: new Date().toISOString(),
                        hash: currentConfigHash
                    })
                });
                console.log('💾 Configuration backup updated');
            }
        }

        // Get existing cronjobs for this module version
        const existingCronjobs = (await takaro.cronjob.cronJobControllerSearch({
            filters: { versionId: [mod.versionId] }
        })).data.data;

        // Legacy cleanup (old format without server ID)
        let legacyCleanupCount = 0;
        for (const existingJob of existingCronjobs) {
            if (/^sm-\d+(-|$)/.test(existingJob.name)) {
                const afterSm = existingJob.name.substring(3);
                if (!/^[a-f0-9]{8}-/i.test(afterSm)) {
                    try {
                        await takaro.cronjob.cronJobControllerRemove(existingJob.id);
                        legacyCleanupCount++;
                        console.log(`🧹 Removed legacy cronjob: ${existingJob.name}`);
                    } catch (error) {
                        console.log(`⚠️ Could not remove legacy cronjob "${existingJob.name}": ${error.message}`);
                    }
                }
            }
        }
        if (legacyCleanupCount > 0) {
            console.log(`🧹 Cleaned up ${legacyCleanupCount} legacy cronjob(s)`);
        }

        const processedJobs = new Set();
        let createdCount = 0;
        let updatedCount = 0;
        let errorCount = 0;

        for (let i = 0; i < cronjobs.length; i++) {
            const job = cronjobs[i];
            const jobNameSuffix = job.name ? `-${job.name}` : '';
            const jobName = `${serverPrefix}${i + 1}${jobNameSuffix}`;

            processedJobs.add(jobName);

            const existingJob = existingCronjobs.find(j => j.name === jobName);

            const jobFunction = `
import { takaro, data } from '@takaro/helpers';
async function main() {
    // Server guard - silently exit if wrong server
    if (data.gameServerId !== '${gameServerId}') return;

    const { gameServerId: gsId } = data;

    const currentPlayers = (await takaro.playerOnGameserver.playerOnGameServerControllerSearch({
        filters: {
            gameServerId: [gsId],
            online: [true]
        }
    })).data.meta;

    if (currentPlayers.total === 0) return;

    await takaro.gameserver.gameServerControllerSendMessage(gsId, {
        message: \`${job.command}\`,
    });
}
await main();
`.trim();

            try {
                if (existingJob) {
                    if (existingJob.temporalValue !== job.temporalValue || existingJob.function !== jobFunction) {
                        await takaro.cronjob.cronJobControllerUpdate(existingJob.id, {
                            name: jobName,
                            temporalValue: job.temporalValue,
                            function: jobFunction
                        });
                        updatedCount++;
                        console.log(`📝 Updated: ${jobName}`);
                    }
                } else {
                    try {
                        await takaro.cronjob.cronJobControllerCreate({
                            name: jobName,
                            temporalValue: job.temporalValue,
                            versionId: mod.versionId,
                            function: jobFunction
                        });
                        createdCount++;
                        console.log(`➕ Created: ${jobName}`);
                    } catch (createError) {
                        if (createError.response?.status === 409) {
                            const conflictJobSearch = await takaro.cronjob.cronJobControllerSearch({
                                filters: { name: [jobName] }
                            });
                            if (conflictJobSearch.data.data.length > 0) {
                                await takaro.cronjob.cronJobControllerUpdate(
                                    conflictJobSearch.data.data[0].id,
                                    { name: jobName, temporalValue: job.temporalValue, function: jobFunction }
                                );
                                updatedCount++;
                                console.log(`📝 Resolved conflict: ${jobName}`);
                            } else {
                                throw createError;
                            }
                        } else {
                            throw createError;
                        }
                    }
                }
            } catch (error) {
                console.log(`❌ Error with "${jobName}": ${error.message || "Unknown error"}`);
                errorCount++;
            }
        }

        // Server-scoped cleanup (only THIS server's orphans)
        let cleanupCount = 0;
        for (const existingJob of existingCronjobs) {
            if (existingJob.name.startsWith(serverPrefix) && !processedJobs.has(existingJob.name)) {
                try {
                    await takaro.cronjob.cronJobControllerRemove(existingJob.id);
                    cleanupCount++;
                    console.log(`🗑️ Removed orphan: ${existingJob.name}`);
                } catch (error) {
                    console.log(`❌ Error removing "${existingJob.name}": ${error.message}`);
                    errorCount++;
                }
            }
        }

        // Update state variables
        try {
            const hashVarSearch = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [configHashKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });

            if (hashVarSearch.data.data.length > 0) {
                await takaro.variable.variableControllerUpdate(hashVarSearch.data.data[0].id, {
                    value: currentConfigHash
                });
            } else {
                await takaro.variable.variableControllerCreate({
                    key: configHashKey,
                    value: currentConfigHash,
                    gameServerId,
                    moduleId: mod.moduleId
                });
            }

            const processedVarSearch = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [lastProcessedKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });

            if (processedVarSearch.data.data.length > 0) {
                await takaro.variable.variableControllerUpdate(processedVarSearch.data.data[0].id, {
                    value: new Date().toISOString()
                });
            } else {
                await takaro.variable.variableControllerCreate({
                    key: lastProcessedKey,
                    value: new Date().toISOString(),
                    gameServerId,
                    moduleId: mod.moduleId
                });
            }
        } catch (stateError) {
            console.log(`⚠️ Could not update state: ${stateError.message}`);
        }

        // Summary
        console.log(`✅ Completed for server ${serverShortId}:`);
        if (createdCount > 0) console.log(`   ➕ ${createdCount} created`);
        if (updatedCount > 0) console.log(`   📝 ${updatedCount} updated`);
        if (cleanupCount > 0) console.log(`   🗑️ ${cleanupCount} orphans removed`);
        if (errorCount > 0) console.log(`   ❌ ${errorCount} errors`);
        if (createdCount === 0 && updatedCount === 0 && cleanupCount === 0) {
            console.log(`   ✓ No changes needed`);
        }

    } catch (error) {
        console.log(`💥 Critical error: ${error.message}`);

        try {
            const backupSearch = await takaro.variable.variableControllerSearch({
                filters: {
                    key: [backupConfigKey],
                    moduleId: [mod.moduleId],
                    gameServerId: [gameServerId]
                }
            });

            if (backupSearch.data.data.length > 0) {
                const backup = JSON.parse(backupSearch.data.data[0].value);
                console.log(`🔄 Backup available from ${backup.timestamp}`);
            }
        } catch (backupError) {
            console.log('⚠️ No backup available');
        }

        throw error;
    }
}

await main();
